const input = $input.first().json.body;

const title = input.title || 'Calm Focus';
const category = input.category || 'Focus';
const mood = input.mood || 'calm, meditative, ambient';
const duration_seconds = input.duration_seconds || 120;

const musicPrompt = `Create a ${mood} audio track for ${category.toLowerCase()}. Style: ambient meditation music with binaural-inspired stereo panning, soft pads, gentle drones, no vocals. Title: ${title}. Duration target: ${Math.round(duration_seconds / 60)} minutes.`;

const imagePrompt = `Abstract digital artwork for a meditation audio track called "${title}". Theme: ${category}. Style: cosmic gradients, deep blues and purples, soft glowing orbs, sound wave visualizations, sacred geometry, aurora lights, dark background, premium minimalist design, no text.`;

return [{
  json: {
    title,
    category,
    mood,
    duration_seconds,
    musicPrompt,
    imagePrompt,
    timestamp: new Date().toISOString()
  }
}];

const response = $input.first().json;

// Extract song ID from Suno response
const songId = response.id || response.song_id || (response.data && response.data[0] && response.data[0].id);

if (!songId) {
  throw new Error('No song ID returned from Suno API. Response: ' + JSON.stringify(response).substring(0, 500));
}

return [{
  json: {
    songId,
    status: 'processing',
    pollCount: 0,
    maxPolls: 60
  }
}];

const response = $input.first().json;
const prevData = $('Extract Song ID').first().json;

const status = response.status || (response.data && response.data.status) || 'unknown';
const pollCount = (prevData.pollCount || 0) + 1;

const audioUrl = response.audio_url || response.song_url || (response.data && response.data.audio_url) || null;
const streamUrl = response.stream_url || (response.data && response.data.stream_url) || null;

return [{
  json: {
    songId: prevData.songId,
    status,
    audioUrl,
    streamUrl,
    pollCount,
    maxPolls: prevData.maxPolls,
    isComplete: status === 'complete' || status === 'completed' || !!audioUrl,
    isFailed: status === 'failed' || status === 'error' || pollCount >= prevData.maxPolls
  }
}];

const sunoData = $('Check Status').first().json;
const promptData = $('Prepare Prompts').first().json;
const imageResponse = $input.first().json;

const imageUrl = imageResponse.data && imageResponse.data[0] && imageResponse.data[0].url;
const revisedPrompt = imageResponse.data && imageResponse.data[0] && imageResponse.data[0].revised_prompt;

return [{
  json: {
    success: true,
    track: {
      title: promptData.title,
      category: promptData.category,
      mood: promptData.mood,
      duration_seconds: promptData.duration_seconds,
      audioUrl: sunoData.audioUrl,
      streamUrl: sunoData.streamUrl,
      songId: sunoData.songId
    },
    coverArt: {
      imageUrl: imageUrl || null,
      revisedPrompt: revisedPrompt || null
    },
    prompts: {
      music: promptData.musicPrompt,
      image: promptData.imagePrompt
    },
    generatedAt: new Date().toISOString()
  }
}];

// Default test payload for manual execution
return [{
  json: {
    body: {
      title: 'Deep Focus Flow',
      category: 'Focus',
      mood: 'calm, rhythmic, ambient, concentration',
      duration_seconds: 120
    }
  }
}];
